<?phpnamespace App\Repository;use App\Entity\BienClient;use DateTime;use Doctrine\Bundle\DoctrineBundle\Repository\ServiceEntityRepository;use Doctrine\ORM\NonUniqueResultException;use Doctrine\ORM\NoResultException;use Doctrine\ORM\QueryBuilder;use Doctrine\Persistence\ManagerRegistry;use Exception;/** * @method BienClient|null find($id, $lockMode = null, $lockVersion = null) * @method BienClient|null findOneBy(array $criteria, array $orderBy = null) * @method BienClient[]    findAll() * @method BienClient[]    findBy(array $criteria, array $orderBy = null, $limit = null, $offset = null) */class BienClientRepository extends ServiceEntityRepository{    public function __construct(ManagerRegistry $registry)    {        parent::__construct($registry, BienClient::class);    }    /**     * @return int|mixed|string     */    public function allBienclientsWithExpertises()    {        return $this->createQueryBuilder('b')            ->leftJoin('b.expertises', 'e')            ->orderBy('b.id', 'ASC')            ->getQuery()            ->getResult();    }    /**     * @param string $sortType     * @return int|mixed|string     */    public function getBienClientSortBy(string $sortType)    {        $array = $this->getProperty($sortType, $sortType);        return $this->createQueryBuilder('b')            ->leftJoin('b.expertises', 'e')            ->leftJoin('b.Quartier', 'q')            ->leftJoin('b.kohUtilisateur', 'u')            ->orderBy('' . $array[0]['property'], '' . $array[0]['type'] . '')            ->getQuery()            ->getResult();    }    /**     * @param $sortType     * @param null $sortDesc     * @param int $userId     * @return int|mixed|string     */    public function getBienClientByClientSortBy($sortType, int $userId, $sortDesc = null)    {        $array = $this->getProperty($sortType, $sortDesc);        return $this->createQueryBuilder('b')            ->leftJoin('b.expertises', 'e')            ->leftJoin('b.Quartier', 'q')            ->leftJoin('b.kohUtilisateur', 'u')            ->leftJoin('e.dossierMbeyan', 'd')            ->leftJoin('e.clientStructure', 'clientStructure')            ->leftJoin('e.typeAcquisition', 'typeAcquisition')            ->leftJoin('e.typeDocumentPropriete', 'typeDocument')            ->leftJoin('e.typeBien', 'typeBien')            ->leftJoin('e.typeUsageBien', 'typeUsage')            ->where('u.id = :userId')            ->setParameter('userId', $userId)            ->orderBy('' . $array[0]['property'], '' . $array[0]['type'])            ->getQuery()            ->getResult();    }    /**     * @param string $sortType     * @param $sortDesc     * @return string[][]     */    public function getProperty(string $sortType, $sortDesc): array    {        if ($sortType === 'quartier') {            $property = 'q.name';            $type = 'ASC';            if ($sortDesc) {                $type = 'DESC';            }        } elseif ($sortType === 'tf') {            $property = 'b.numeroDocument';            $type = 'ASC';            if ($sortDesc) {                $type = 'DESC';            }        } elseif ($sortType === 'expertise') {            $property = 'e.numeroExpertise';            $type = 'ASC';            if ($sortDesc) {                $type = 'DESC';            }        } elseif ($sortType === 'client') {            $property = 'u.firstName';            $type = 'ASC';            if ($sortDesc) {                $type = 'DESC';            }        } elseif ($sortType === 'price') {            $property = 'e.lastEvaluationPrice';            $type = 'ASC';            if ($sortDesc) {                $type = 'DESC';            }        } elseif ($sortType === 'numero_mbeyan') {            $property = 'd.numeroDossier';            $type = 'ASC';            if ($sortDesc) {                $type = 'DESC';            }        } elseif ($sortType === 'proprietaire') {            $property = 'clientStructure.name';            $type = 'ASC';            if ($sortDesc) {                $type = 'DESC';            }        } elseif ($sortType === 'type_acquisition') {            $property = 'typeAcquisition.name';            $type = 'ASC';            if ($sortDesc) {                $type = 'DESC';            }        } elseif ($sortType === 'type_document') {            $property = 'typeDocument.name';            $type = 'ASC';            if ($sortDesc) {                $type = 'DESC';            }        } elseif ($sortType === 'type_bien') {            $property = 'typeBien.name';            $type = 'ASC';            if ($sortDesc) {                $type = 'DESC';            }        } elseif ($sortType === 'type_usage') {            $property = 'typeUsage.name';            $type = 'ASC';            if ($sortDesc) {                $type = 'DESC';            }        } elseif ($sortType === 'superficie') {            $property = 'e.superficie';            $type = 'ASC';            if ($sortDesc) {                $type = 'DESC';            }        } elseif ($sortType === 'derniere_expertise') {            $property = 'e.dateEvaluation';            $type = 'ASC';            if ($sortDesc) {                $type = 'DESC';            }        } elseif ($sortType === 'prochaine_expertise') {            $property = 'e.dateNextEvaluation';            $type = 'ASC';            if ($sortDesc) {                $type = 'DESC';            }        } elseif ($sortType === 'created_at') {            $property = 'e.createdAt';            $type = 'ASC';            if ($sortDesc) {                $type = 'DESC';            }        } else {            $property = 'b.id';            $type = 'DESC';        }        return array(['property' => $property, 'type' => $type]);    }    /**     * @param $type     * @return BienClient[]     */    public function bien_by_type_client($type): array    {        $query = $this->createQueryBuilder('b');        if ($type === 'structure') {            $query->andWhere('b.isForStructure = true');        }        if ($type === 'particulier') {            $query->andWhere('b.isForStructure = false');        }        return $query->getQuery()            ->getResult();    }    /**     * @param array $critere     * @return int|mixed|string     */    public function getBienByCritere(array $critere)    {        $query = $this->createQueryBuilder('b');        $query->leftJoin('b.kohUtilisateur', 'u');        $query->leftJoin('b.expertises', 'e');        if (array_key_exists('typeClient', $critere)) {            $query->leftJoin('u.typeCompte', 'typeCompte');            $query->andWhere('typeCompte.id = :typeCompteID')                ->setParameter('typeCompteID', $critere['typeClient']);        }        if (array_key_exists('client', $critere)) {            $query->andWhere('u.id = :userID')                ->setParameter('userID', $critere['client']);        }        $query = $this->getQueryWithCritere($query, $critere);        return $query->getQuery()->getResult();    }    /**     * @param array $critere     * @param int $userId     * @return int|mixed|string     */    public function getBienByCritereAndUser(array $critere, int $userId)    {        $query = $this->createQueryBuilder('b');        $query->leftJoin('b.kohUtilisateur', 'u')            ->where('u.id = :userId');        $query->leftJoin('b.expertises', 'e');        $query->setParameter('userId', $userId);        $query = $this->getQueryWithCritere($query, $critere);        return $query->getQuery()->getResult();    }    /**     * @param QueryBuilder $query     * @param $critere     * @return QueryBuilder     */    public function getQueryWithCritere(QueryBuilder $query, $critere): QueryBuilder    {        if (array_key_exists('numeroCompteClientStructure', $critere)) {            $numeroCompte = $critere['numeroCompteClientStructure'];            $query->leftJoin('e.clientStructure', 'clientStructure')                ->andWhere('clientStructure.name LIKE :numeroCompte')                ->setParameter('numeroCompte', '%' . $numeroCompte . '%');        }        if (array_key_exists('tf', $critere)) {            $tf = $critere['tf'];            $query->andWhere('b.numeroDocument LIKE :numeroDoc')                ->setParameter('numeroDoc', '%' . $tf . '%');        }        if (array_key_exists('quartierFilter', $critere)) {            $query->leftJoin('b.Quartier', 'quartier');            $query->andWhere('quartier.id =:quartier')                ->setParameter('quartier', $critere['quartierFilter']);        }        if (array_key_exists('regionFilter', $critere)) {            $query->leftJoin('b.Quartier', 'quartier1')                ->leftJoin('quartier1.commune', 'commune1')                ->leftJoin('commune1.cercle', 'cercle1')                ->leftJoin('cercle1.region', 'region1')                ->andWhere('region1.id = :region1')                ->setParameter('region1', $critere['regionFilter']);        }        if (array_key_exists('cercleFilter', $critere)) {            $query->leftJoin('b.Quartier', 'quartier2')                ->leftJoin('quartier2.commune', 'commune2')                ->leftJoin('commune2.cercle', 'cercle2')                ->andWhere('cercle2.id = :cercle2')                ->setParameter('cercle2', $critere['cercleFilter']);        }        if (array_key_exists('numeroExpertise', $critere)) {            $query->andWhere('e.numeroExpertise LIKE :numeroExpertise')                ->setParameter('numeroExpertise', '%' . $critere['numeroExpertise'] . '%');        }        if (array_key_exists('numeroMbeyan', $critere)) {            $query->leftJoin('e.dossierMbeyan', 'dossier_mbeyan')                ->andWhere('dossier_mbeyan.numeroDossier LIKE :numeroMbeyan')                ->setParameter('numeroMbeyan', '%' . $critere['numeroMbeyan'] . '%');        }        if (array_key_exists('dateFinDation', $critere) && array_key_exists('dateDebutDation', $critere)) {            $dateInf = date($critere['dateDebutDation']);            $dateSup = date($critere['dateFinDation']);            $query->andWhere('e.dateFinDation BETWEEN :dateInf and :dateSup')                ->setParameter('dateInf', $dateInf)                ->setParameter('dateSup', $dateSup);        }        if (array_key_exists('dateFinImmobilisation', $critere) && array_key_exists('dateDebutImmobilisation', $critere)) {            $dateInf = date($critere['dateDebutImmobilisation']);            $dateSup = date($critere['dateFinImmobilisation']);            $query->andWhere('e.dateSortieImmobilisation BETWEEN :dateInf and :dateSup')                ->setParameter('dateInf', $dateInf)                ->setParameter('dateSup', $dateSup);        }        if (array_key_exists('typeDocument', $critere)) {            $query->leftJoin('e.typeDocumentPropriete', 'typedocumentpropriete');            $query->andWhere('typedocumentpropriete.id = :typeDocumentID')                ->setParameter('typeDocumentID', $critere['typeDocument']);        }        if (array_key_exists('typeAcquisition', $critere)) {            $query->leftJoin('e.typeAcquisition', 'typeAcquisition');            $query->andWhere('typeAcquisition.id IN (:typeAcquisitionID)')                ->setParameter('typeAcquisitionID', $critere['typeAcquisition']);        }        if (array_key_exists('typeUsageBien', $critere)) {            $query->leftJoin('e.typeUsageBien', 'type_usage_bien')                ->andWhere('type_usage_bien.id = :typeUsageBienId')                ->setParameter('typeUsageBienId', $critere['typeUsageBien']);        }        if (array_key_exists('typeBien', $critere)) {            $query->leftJoin('e.typeBien', 'type_bien')                ->andWhere('type_bien.id = :typeBienId')                ->setParameter('typeBienId', $critere['typeBien']);        }        if (array_key_exists('prixEstimationInf', $critere) && array_key_exists('prixEstimationSup', $critere)) {            $prixInf = $critere['prixEstimationInf'];            $prixSup = $critere['prixEstimationSup'];            $query->andWhere('e.lastEvaluationPrice >= :prixInf')                ->andWhere('e.lastEvaluationPrice <= :prixSup')                ->setParameter('prixInf', $prixInf)                ->setParameter('prixSup', $prixSup);        }        if (array_key_exists('dateInfLastEvaluation', $critere) && array_key_exists('dateSupLastEvaluation', $critere)) {            $dateInf = date($critere['dateInfLastEvaluation']);            $dateSup = date($critere['dateSupLastEvaluation']);            $query->andWhere('e.dateEvaluation BETWEEN :dateInf and :dateSup')                ->setParameter('dateInf', $dateInf)                ->setParameter('dateSup', $dateSup);        }        if (array_key_exists('dateInfNextEvaluation', $critere) && array_key_exists('dateSupNextEvaluation', $critere)) {            $dateInf1 = date($critere['dateInfNextEvaluation']);            $dateSup1 = date($critere['dateSupNextEvaluation']);            $query->andWhere('e.dateNextEvaluation BETWEEN :dateInf and :dateSup')                ->setParameter('dateInf', $dateInf1)                ->setParameter('dateSup', $dateSup1);        }        return $query;    }    /**     * @param $value     * @return BienClient[] Returns an array of BienClient objects     */    public function bien_client($value): array    {        return $this->createQueryBuilder('b')            ->leftjoin('b.kohUtilisateur', 'koh_utilisateur')            ->andWhere('koh_utilisateur.id = :val')            ->setParameter('val', $value)            ->orderBy('b.id', 'ASC')            ->getQuery()            ->getResult();    }    /**     * @param $value     * @return int|mixed|string     */    public function bien_client_by_numero($value)    {        return $this->createQueryBuilder('b')            ->andWhere('b.numeroDocument LIKE :val')            ->setParameter('val', '%' . $value . '%')            ->getQuery()            ->getResult();    }    /**     * @param $id     * @return int|mixed|string     */    public function bien_client_by_client_and_critere($id)    {        return $this->createQueryBuilder('b')            ->leftJoin('b.kohUtilisateur', 'kohUtilisateur')            ->andWhere('kohUtilisateur.id = :id')            ->setParameter('id', $id)            ->getQuery()            ->getResult();    }    /**     * @param int $structureId     * @return mixed     * @throws NoResultException     * @throws NonUniqueResultException     */    public function countStructureBiens(int $structureId)    {        return $this->createQueryBuilder('b')            ->leftJoin('b.kohUtilisateur', 'kohUtilisateur')            ->leftJoin('kohUtilisateur.structure', 'structure')            ->where('structure.id =:structureId')            ->select('count(b.id)')            ->setParameter('structureId', $structureId)            ->getQuery()->getSingleScalarResult();    }    // /**    //  * @return BienClient[] Returns an array of BienClient objects    //  */    /*    public function findByExampleField($value)    {        return $this->createQueryBuilder('b')            ->andWhere('b.exampleField = :val')            ->setParameter('val', $value)            ->orderBy('b.id', 'ASC')            ->setMaxResults(10)            ->getQuery()            ->getResult()        ;    }    */    /*    public function findOneBySomeField($value): ?BienClient    {        return $this->createQueryBuilder('b')            ->andWhere('b.exampleField = :val')            ->setParameter('val', $value)            ->getQuery()            ->getOneOrNullResult()        ;    }    */}